import{_ as e,o,c as t,ae as r}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Welcoming ROI Hub to GA","description":"","frontmatter":{"title":"Welcoming ROI Hub to GA","slug":"welcoming-roi-hub-to-ga"},"headers":[],"relativePath":"account-hub/welcoming-roi-hub-to-ga.md","filePath":"account-hub/welcoming-roi-hub-to-ga.md"}'),i={name:"account-hub/welcoming-roi-hub-to-ga.md"};function n(l,a,s,c,u,h){return o(),t("div",null,[...a[0]||(a[0]=[r('<p>The highly anticipated GA release of ROI Hub is finally here! ROI Hub centralizes all your cost and attributed revenue data, eliminating the need for manual consolidation.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>ROI Hub helps you get comprehensive return on investment insights and analyze cost data ingestion with Branch.</p><p>With improved cost data support and the ability to upload cost in several different ways, you have access to 100% cost coverage across all your ad partners.</p><p>Plus, granular reporting and automated alerts for connection issues keep you one step ahead, allowing you to focus on optimizing growth!</p><h2 id="upload-cost-data" tabindex="-1">Upload Cost Data <a class="header-anchor" href="#upload-cost-data" aria-label="Permalink to &quot;Upload Cost Data&quot;">​</a></h2><p>Branch offers various ways for you to upload cost data for analysis. To get this data to Branch, use one of the following methods:</p><ul><li><a href="./cost-data-via-file-upload.html">File Upload</a></li><li><a href="./cost-data-via-api-connection.html">Direct Integration</a></li><li><a href="./cost-data-via-scheduled-ingestion.html">Scheduled Email Ingestion</a></li><li><a href="./cost-on-links.html">Ad Link Parameter Tracking</a></li></ul><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><p>Access to ROI Hub requires a premium plan. Please <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">contact our Sales team</a> to learn more about pricing and availability.</p><h2 id="learn-more" tabindex="-1">Learn More <a class="header-anchor" href="#learn-more" aria-label="Permalink to &quot;Learn More&quot;">​</a></h2><p>To learn more about ROI Hub, visit our <a href="./roi-hub.html">guide</a>.</p>',12)])])}const m=e(i,[["render",n]]);export{p as __pageData,m as default};
